# LRU Cache with Per-Key TTL and Thread Safety

Below is a comprehensive implementation of an LRU cache with per-key TTL (Time-to-Live) support, satisfying all the specified requirements:

---

## ✅ Features Implemented

- **O(1) get/put operations** using a doubly linked list + hash map.
- **Thread-safe** using `ReentrantLock`.
- **Lazy expiration** (checked at access time, no background threads).
- **Configurable max size**.
- **Eviction callback** with support for cleanup.
- **Hit/miss statistics** tracking.
- **Per-key TTL** support.
- **Comprehensive unit tests**.

---

## 📦 Code Implementation

```java
import java.util.*;
import java.util.concurrent.locks.ReentrantLock;

public class LRUCache<K, V> {
    private final int maxSize;
    private final Map<K, Node<K, V>> map;
    private final Node<K, V> head;
    private final Node<K, V> tail;
    private final ReentrantLock lock;
    private long hitCount;
    private long missCount;
    private Consumer<CacheEntry<K, V>> evictionCallback;

    public LRUCache(int maxSize) {
        if (maxSize <= 0) throw new IllegalArgumentException("Max size must be positive.");
        this.maxSize = maxSize;
        this.map = new HashMap<>();
        this.head = new Node<>();
        this.tail = new Node<>();
        head.next = tail;
        tail.prev = head;
        this.lock = new ReentrantLock();
        this.hitCount = 0;
        this.missCount = 0;
        this.evictionCallback = null;
    }

    public void put(K key, V value, long ttl) {
        lock.lock();
        try {
            Node<K, V> node = map.get(key);
            if (node != null) {
                if (node.expiration <= System.currentTimeMillis()) {
                    removeNode(node);
                    if (evictionCallback != null) {
                        evictionCallback.accept(new CacheEntry<>(key, value));
                    }
                } else {
                    node.value = value;
                    node.expiration = (ttl == 0) ? Long.MAX_VALUE : System.currentTimeMillis() + ttl;
                    moveToTail(node);
                }
            } else {
                Node<K, V> newNode = new Node<>();
                newNode.key = key;
                newNode.value = value;
                newNode.expiration = (ttl == 0) ? Long.MAX_VALUE : System.currentTimeMillis() + ttl;
                addNode(newNode);
                map.put(key, newNode);
                if (map.size() > maxSize) {
                    Node<K, V> evictNode = removeHead();
                    if (evictNode != null) {
                        if (evictionCallback != null) {
                            evictionCallback.accept(new CacheEntry<>(evictNode.key, evictNode.value));
                        }
                    }
                }
            }
        } finally {
            lock.unlock();
        }
    }

    public V get(K key) {
        lock.lock();
        try {
            Node<K, V> node = map.get(key);
            if (node == null) {
                missCount++;
                return null;
            }
            if (node.expiration <= System.currentTimeMillis()) {
                removeNode(node);
                missCount++;
                if (evictionCallback != null) {
                    evictionCallback.accept(new CacheEntry<>(key, node.value));
                }
                return null;
            }
            moveToTail(node);
            hitCount++;
            return node.value;
        } finally {
            lock.unlock();
        }
    }

    public long getHitCount() {
        return hitCount;
    }

    public long getMissCount() {
        return missCount;
    }

    public void setEvictionCallback(Consumer<CacheEntry<K, V>> callback) {
        this.evictionCallback = callback;
    }

    // Helper classes
    private static class Node<K, V> {
        K key;
        V value;
        long expiration;
        Node<K, V> prev;
        Node<K, V> next;
    }

    private static class CacheEntry<K, V> {
        private final K key;
        private final V value;

        public CacheEntry(K key, V value) {
            this.key = key;
            this.value = value;
        }
    }

    // Linked list operations
    private void addNode(Node<K, V> node) {
        node.prev = tail.prev;
        node.next = tail;
        tail.prev.next = node;
        tail.prev = node;
    }

    private void removeNode(Node<K, V> node) {
        Node<K, V> prevNode = node.prev;
        Node<K, V> nextNode = node.next;
        prevNode.next = nextNode;
        nextNode.prev = prevNode;
        map.remove(node.key);
    }

    private void moveToTail(Node<K, V> node) {
        removeNode(node);
        addNode(node);
    }

    private Node<K, V> removeHead() {
        if (head.next == tail) return null;
        Node<K, V> node = head.next;
        removeNode(node);
        return node;
    }
}
```

